                                            </p>
                                        </td>
                                        <td style={{ padding: '16px 28px' }}>
                                            {getStatusBadge(ticket.status)}
                                        </td>
                                        <td style={{ padding: '16px 28px', whiteSpace: 'nowrap' }}>
