                        <Ticket className="text-emerald-600 w-8 h-8" /> My Tickets
                    </h1>
                    <p className="text-gray-500 font-medium mt-1">Manage and track your support requests</p>
                </div>
                <button
                    onClick={() => navigate('/create-ticket')}
