const TicketDetail = () => {
    const { ticket_id } = useParams();
    const navigate = useNavigate();
    const [ticket, setTicket] = useState(null);
    const [loading, setLoading] = useState(true);
    const [isReopening, setIsReopening] = useState(false);
    const [showCsat, setShowCsat] = useState(false);

    useEffect(() => {
        window.scrollTo(0, 0);

        const fetchInitialTicket = async () => {
            setLoading(true);
            try {
                const { data, error } = await supabase
                    .from('tickets')
                    .select('*')
                    .eq('id', ticket_id)
                    .single();

                if (error) throw error;
                if (data) {
                    setTicket({
                        ...data,
                        ticket_id: data.id,
                        text: data.description,
                        summary: data.subject,
                    });
                }
            } catch (err) {
                console.error("Error fetching ticket:", err);
            } finally {
                setLoading(false);
            }
        };

        fetchInitialTicket();

        // 3. Subscribe to REAL-TIME updates for THIS ticket
        const channel = supabase
            .channel(`ticket_update_${ticket_id}`)
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'tickets',
                    filter: `id=eq.${ticket_id}`
                },
                (payload) => {
                    console.log("Real-time ticket update received:", payload.new);
                    setTicket(prev => ({
                        ...prev,
                        ...payload.new,
                        ticket_id: payload.new.id,
                        text: payload.new.description,
                        summary: payload.new.subject,
                    }));
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [ticket_id]);

    // Show CSAT modal if ticket is resolved and not yet rated
    useEffect(() => {
        if (ticket?.status?.toLowerCase()?.includes('resolv') && !ticket.csat_rating) {
