                        </h2>

                        <div className="mb-5">
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider">Confidence Score</span>
                                <span className="font-mono text-xs font-black text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-md">
                                    {Math.round(confidenceScore * 100)}%
                                </span>
                            </div>
                            <div className="w-full bg-gray-200 rounded-full h-1.5">
                                <div className="bg-emerald-500 h-1.5 rounded-full" style={{ width: `${Math.round(confidenceScore * 100)}%` }}></div>
                            </div>
                        </div>

                        <div>
                            <p className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-3">Extracted Entities</p>
                            {entities.length > 0 ? (
                                <div className="flex flex-wrap gap-2">
                                    {entities.map((entity, i) => (
                                        <span key={i} className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-md text-xs font-semibold bg-white border border-gray-200 text-gray-700 shadow-sm">
                                            {typeof entity === 'string' ? entity : entity.text || JSON.stringify(entity)}
                                        </span>
                                    ))}
                                </div>
                            ) : (
                                <p className="text-sm text-gray-500 italic">No specific entities detected.</p>
                            )}
                        </div>
                    </Card>

                    {/* Card 4: Screenshot */}
                        <div className="p-6 bg-emerald-900 rounded-2xl border border-emerald-800 text-center shadow-xl">
                            <p className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.2em] mb-2">Registration Timestamp</p>
                            <p className="text-sm font-bold text-white leading-relaxed">
                                {formatFullTimestamp(ticket.created_at)}
                            </p>
                        </div>
                    <Card className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                        <h2 className="text-sm font-bold text-gray-900 uppercase tracking-widest mb-4 flex items-center gap-2">
                            <ImageIcon className="w-4 h-4 text-gray-400" /> Attached Media
                        </h2>
                        {(ticket.image_url || ticket.image || ticket.capturedFileBase64) ? (
                            <div
                                className="rounded-xl overflow-hidden border border-gray-100 bg-gray-50 cursor-pointer group relative"
                                onClick={() => window.open(ticket.image_url || ticket.image || ticket.capturedFileBase64, '_blank')}
                            >
                                <img
                                    src={ticket.image_url || ticket.image || ticket.capturedFileBase64}
                                    alt="User uploaded screenshot"
                                    className="w-full h-auto object-cover max-h-[200px] group-hover:opacity-90 transition-opacity"
                                />
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/10 transition-opacity">
                                    <span className="bg-white/90 text-gray-800 text-xs font-bold px-3 py-1.5 rounded-lg shadow-sm">Click to view full image</span>
                                </div>
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center py-6 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                                <ImageIcon className="w-8 h-8 text-gray-300 mb-2" />
                                <p className="text-xs font-medium text-gray-500">No screenshot provided</p>
                            </div>
                        )}
                    </Card>

                    {/* Card 5: Suggested Solution */}
                    <Card className="p-6 rounded-2xl border border-emerald-100 shadow-sm bg-gradient-to-br from-emerald-50/50 to-white relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full blur-3xl -mr-10 -mt-10"></div>
                        <h2 className="text-sm font-bold text-gray-900 uppercase tracking-widest mb-4 flex items-center gap-2 relative z-10">
                            <Zap className="w-4 h-4 text-emerald-500 fill-emerald-500" /> Resolution
                        </h2>

                        <div className="relative z-10">
                            {isAutoResolved ? (
                                <div>
                                    <p className="text-sm font-bold text-emerald-800 mb-3">Suggested Solution</p>
                                    <div className="space-y-3">
                                        {solutionSteps.length > 0 ? (
                                            solutionSteps.map((step, idx) => (
                                                <div key={idx} className="flex gap-3 text-sm">
                                                    <div className="mt-0.5 w-5 h-5 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center flex-shrink-0 font-bold text-xs">
                                                        {idx + 1}
                                                    </div>
                                                    <p className="text-gray-700 font-medium leading-relaxed">{step}</p>
                                                </div>
                                            ))
                                        ) : (
                                            <p className="text-sm text-gray-600">The AI provided an automated resolution to this issue.</p>
                                        )}
                                    </div>
                                    <button className="w-full mt-5 px-4 py-2 bg-white border border-gray-200 text-gray-700 rounded-lg text-sm font-bold hover:bg-gray-50 transition shadow-sm">
                                        Did this help?
                                    </button>
                                </div>
                            ) : ticket.status === 'resolved' ? (
                                <div className="flex flex-col gap-4">
                                    <div className="flex gap-3 text-sm">
                                        <div className="mt-0.5 w-5 h-5 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center flex-shrink-0 font-bold text-xs">
                                            <CheckCircle2 size={12} />
                                        </div>
                                        <p className="text-gray-700 font-medium leading-relaxed">
                                            This ticket was resolved by human support from the <span className="font-bold text-gray-900">{ticket.assigned_team || 'Support'}</span> team.
                                        </p>
                                    </div>

                                    <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mt-2">
                                        <p className="text-amber-800 text-sm font-bold mb-2">Issue not fully resolved?</p>
                                        <button
                                            onClick={handleReopen}
                                            disabled={isReopening}
                                            className="w-full flex items-center justify-center gap-2 px-4 py-2 bg-white border border-amber-200 text-amber-700 rounded-lg text-sm font-bold hover:bg-amber-50 transition shadow-sm disabled:opacity-50"
                                        >
                                            {isReopening ? <Loader2 size={16} className="animate-spin" /> : <RotateCcw size={16} />}
                                            Reopen Ticket
                                        </button>
                                    </div>
                                </div>
                            ) : (
                                <div className="flex flex-col">
                                    <div className="flex gap-3 text-sm">
                                        <div className="mt-0.5 w-5 h-5 rounded-full bg-amber-100 text-amber-600 flex items-center justify-center flex-shrink-0 font-bold text-xs">
                                            <UserCog size={12} />
                                        </div>
                                        <p className="text-gray-700 font-medium leading-relaxed">
                                            This ticket has been escalated to human support. The <span className="font-bold text-gray-900">{ticket.assigned_team || 'Support'}</span> team is currently reviewing it.
                                        </p>
                                    </div>
                                </div>
                            )}
                        </div>
                    </Card>

                </div>
            </div>

            {/* CSAT Modal */}
            {showCsat && (
                <CSATModal
                    ticketId={ticket.ticket_id}
                    onSubmit={() => {
                        setShowCsat(false);
                        setTicket(prev => ({ ...prev, csat_rating: 1 })); // dummy, prevents re-showing
                    }}
                    onDismiss={() => setShowCsat(false)}
                />
            )}
        </main>
    );
};

export default TicketDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    Activity, CheckCircle2, ShieldCheck, User,
    Clock, ArrowRight, Loader2, FileText, Zap
} from 'lucide-react';
import useTicketStore from "../../store/ticketStore";
import useAuthStore from "../../store/authStore";
import { supabase } from "../../lib/supabaseClient";
import { Card, CardContent } from "../../components/ui/card";
import TicketTimeline from "../components/TicketTimeline";
import axios from 'axios';
import { API_CONFIG } from '../../config';

const TicketTracking = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { aiTicket } = useTicketStore();
    const { user, profile } = useAuthStore();
    const [isCreating, setIsCreating] = useState(true);
    const [error, setError] = useState(null);
    const [createdTicket, setCreatedTicket] = useState(null);
    const hasCreated = useRef(false);
    const resolutionSteps = location.state?.resolutionSteps || [];
    useEffect(() => {
        if (!aiTicket) {
            navigate('/create-ticket');
            return;
        }

        const finalizeTracking = async () => {
            if (hasCreated.current) return;
            hasCreated.current = true;

            try {
                // Determine the correct status
                const isAutoResolved = aiTicket.auto_resolve || false;
                const status = isAutoResolved ? 'auto_resolved' : 'pending_human';

                // Map AI Analysis into the TicketSaveRequest format
                const savePayload = {
                    user_id: user?.id,
                    subject: aiTicket.summary,
                    description: aiTicket.originalIssue || aiTicket.summary,
                    category: aiTicket.category,
                    subcategory: aiTicket.subcategory,
                    priority: aiTicket.priority,
                    assigned_team: aiTicket.assigned_team,
                    status: status,
                    auto_resolve: isAutoResolved,
                    is_duplicate: aiTicket.duplicate_ticket?.is_duplicate || false,
                    confidence: aiTicket.confidence,
                    image_url: aiTicket.image_url || null,
                    company: profile?.company || "System",
                    sla_breach_at: aiTicket.sla_breach_at,
                    metadata: {
                        confidence: aiTicket.confidence,
                        entities: aiTicket.entities,
                        decision_factors: aiTicket.decision_factors,
                        ocr_text: aiTicket.ocr_text,
                        image_description: aiTicket.image_description
                    },
                    entities: aiTicket.entities,
                    solution_steps: resolutionSteps,
                    ocr_text: aiTicket.ocr_text || "",
                    needs_review: aiTicket.needs_review,
                    routing_confidence: aiTicket.confidence
                };

                const res = await axios.post(`${API_CONFIG.BACKEND_URL}/tickets/save`, savePayload);

                if (res.data?.ticket_id) {
                    const newTicket = { ...aiTicket, id: res.data.ticket_id, ticket_id: res.data.ticket_id, status };
                    setCreatedTicket(newTicket);
                    setIsCreating(false);

                    // Redirect to the detail page after a short confirmation pause
                    setTimeout(() => {
                        navigate(`/ticket/${res.data.ticket_id}`);
                    }, 2500);
                } else {
                    throw new Error("Failed to retrieve ID from backend.");
                }
            } catch (err) {
                console.error("Tracking Error:", err);
                setError(err.message || "Failed to create ticket.");
                setIsCreating(false);
            }
        };

        finalizeTracking();
    }, [aiTicket, navigate, user, profile?.company, resolutionSteps]);

    if (!aiTicket) return null;

    return (
        <div className="min-h-screen bg-[#f6f8f7] flex flex-col items-center justify-center px-6">
            <div className="w-full max-w-[500px] text-center space-y-8">

                {/* Animation Section */}
                <div className="relative inline-block">
                    <div className="absolute inset-0 bg-emerald-500 blur-3xl opacity-20 rounded-full animate-pulse"></div>
                    <div className="relative w-24 h-24 bg-white rounded-3xl shadow-xl shadow-emerald-900/5 border border-emerald-50 flex items-center justify-center mx-auto">
                        {isCreating ? (
                            <Activity className="w-10 h-10 text-emerald-600 animate-spin" />
                        ) : error ? (
                            <Clock className="w-10 h-10 text-red-500" />
                        ) : (
                            <CheckCircle2 className="w-10 h-10 text-emerald-600 animate-bounce" />
                        )}
                    </div>
                </div>

                <div className="space-y-3">
                    <h1 className="text-2xl font-black text-gray-900 tracking-tight">
                        {isCreating ? "Escalating to Specialists" : error ? "Something went wrong" : "Successfully Escalated"}
                    </h1>
                    <p className="text-gray-500 font-medium leading-relaxed">
                        {isCreating
                            ? `We're assigning your ${aiTicket.category || 'support'} request to the right team.`
                            : error
                                ? error
                                : "Your ticket has been created and assigned. Redirecting to tracking..."
                        }
                    </p>
                </div>

                {/* Dynamic Status Steps — shows real AI data */}
                <Card className="rounded-2xl border border-gray-100 shadow-sm bg-white overflow-hidden text-left">
                    <CardContent className="p-6 space-y-5">
                        <div className="flex items-center gap-4 text-emerald-600 font-bold text-sm">
                            <CheckCircle2 className="w-4 h-4" />
                            <span>AI Analysis Complete</span>
                            <span className="ml-auto text-[10px] font-bold text-gray-300 uppercase tracking-wider">
                                {aiTicket.category || 'General'}
                            </span>
                        </div>
                        <div className={`flex items-center gap-4 text-sm font-bold ${isCreating ? 'text-gray-400' : error ? 'text-red-500' : 'text-emerald-600'}`}>
                            {isCreating ? <Loader2 className="w-4 h-4 animate-spin text-emerald-500" /> : error ? <Clock className="w-4 h-4" /> : <CheckCircle2 className="w-4 h-4" />}
                            <span>{error ? 'Failed to create ticket' : 'Creating Support Ticket'}</span>
                        </div>
                        <div className={`flex items-center gap-4 text-sm font-bold ${createdTicket ? 'text-emerald-600' : 'text-gray-400'}`}>
                            {createdTicket ? <CheckCircle2 className="w-4 h-4" /> : <Clock className="w-4 h-4" />}
                            <span>
                                {createdTicket
                                    ? `Assigned → ${createdTicket.assigned_team}`
                                    : 'Agent Assignment Pending'}
                            </span>
                        </div>
                    </CardContent>
                </Card>

                {/* Dynamic Ticket Timeline — passes the REAL ticket with Supabase data */}
                {createdTicket && <TicketTimeline ticket={createdTicket} />}

            </div>
        </div>
    );
};

export default TicketTracking;
